mapper.select:
SELECT * FROM chat_history
WHERE session_id = #{sessionId}
ORDER BY created_at ASC

SELECT * FROM chat_history
WHERE user_id = #{userId}
ORDER BY created_at ASC

mapper.delete:
DELETE FROM chat_history
WHERE session_id = #{sessionId}
AND id IN (
    SELECT id FROM (
        SELECT id FROM chat_history
        WHERE session_id = #{sessionId}
        ORDER BY created_at ASC
        LIMIT #{limit}
    ) AS old_records
)
